<?php namespace App\Controllers; use App\Models\User; use App\Database\Database; class UserController { private User $user; public function __construct() { $this->user = new User(); } public function create(): void { if ($_SERVER['REQUEST_METHOD'] === 'POST') { $this->user->setName($_POST['name'] ?? ''); $this->user->setEmail($_POST['email'] ?? ''); if ($this->user->save()) { header('Location: /index.php?success=1'); exit; } } } public function listAll(): array { return User::getAll(); } public function get(int $id): ?array { return User::getById($id); } public function delete(int $id): void { if (User::delete($id)) { header('Location: /index.php?deleted=1'); exit; } http_response_code(404); } } ?>